head.script:
scwin.sDate = $c.date.formatDateTime(new Date());
scwin.vCurDate = $c.date.getServerDateTime();
scwin.vQryStDt = $c.date.getDateAddMonthDirection(scwin.vCurDate, 0 , "F");  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vQryEndDt = $c.date.getDateAddMonthDirection(scwin.vCurDate, 0 , "L");  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자) 
scwin.vEmpNo = ""; 

scwin.onpageload = function () {
    scwin.vEmpNo = $c.gus.cfIsNull($c.data.getMemInfo("empNo")) ? '' : $c.data.getMemInfo("empNo"); 
    ds_condition.insertRow();
    ds_condition.setRowPosition(0);

    gr_purchaseCerti.setColumnStyle("button", "color", "#006fdf");
    gr_purchaseCerti.setColumnStyle("button", "text-decoration", "underline");
    gr_purchaseCerti.setColumnStyle("button", "cursor", "pointer");

    const codeOptions = [
         { grpCd : "SD070", compID : "acb_taxnClsCd,gr_purchaseCerti:taxnClsCd", opt:{"range":"1"} } // 과세구분
    ];
    $c.data.setCommonCode(codeOptions);
};


scwin.onUdcCompleted = function () {
    udc_qryConDt.setInitDate(scwin.vQryStDt, scwin.vQryEndDt);
    acb_qryDtConKnd.setValue("CERTI"); 

    acb_taxnClsCd.setValue("01");  
    ed_homeClntNo.focus();

    // 테스트 데이터
    // acb_qryDtConKnd.setValue("POST"); 
    // udc_qryConDt.setInitDate("20190101", "20241231");

};

scwin.ondataload = function () {
   // acb_taxnClsCd.setValue("02");
};

//-------------------------------------------------------------------------
// Function
//-------------------------------------------------------------------------
// 거래명세서 조회
scwin.f_Retrieve = async function () {
    // validation check
    if (!await $c.gus.cfValidate([ed_homeClntNo])) {
        return;
    }

    // 조회시작일자가 더 클경우 체크
    if (!await $c.gus.cfIsAfterDate(ed_qryConDtFm.getValue(), ed_qryConDtTo.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    }

    let e = await $c.sbm.execute(sbm_searchCertiList);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_searchCertiList_submitdone(e);
    }
};

// 팝업창 처리
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList  = new Array();  // 공통POP-UP -> 요청화면

    switch (disGubun) {
        case 1: // 소속거래처
            udc_homeClntNo.setSelectId("retrieveSubsidaryClntListJa"); 
            rtnList = await udc_homeClntNo.cfCommonPopUpAsync(
                                                                    ''   	                            // XML상의 SELECT ID
                                                                    , pCode								// 화면에서의 ??? Code Element의	Value
                                                                    , pName								// 화면에서의 ??? Name Element의	Value
                                                                    , pClose							// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                                                    , '5'								// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                                                    , null								// Title순서
                                                                    , '150,170'  		    			// 보여주는 각 컬럼들의 폭
                                                                    , null								// 컬럼중에서 숨기는	컬럼 지정
                                                                    , null								// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                                                    , null								// POP-UP뛰을때 원도우의	사용자 정의	폭
                                                                    , null								// POP-UP뛰을때 우도우의	사용자 정의	높이
                                                                    , null								// 윈도우 위치 Y좌표
                                                                    ,  null								// 윈도우 위치 X좌표
                                                                    , null								// 중복체크여부	("F")
                                                                    , pAllSearch						// 전체검색허용여부	("F")
                                                                    , "소속거래처,거래처코드,거래처명"	  // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                            );
            if (rtnList != null) {
                $c.gus.cfSetReturnValue(rtnList, ed_homeClntNo, ed_homeClntNm);
            }
        break;

        case 2:
            // 차량번호
            udc_vehclNo.setSelectId("retrieveSubsidaryVehclList"); 
            rtnList = await udc_vehclNo.cfCommonPopUpAsync(
                                                                ''   	                          // XML상의 SELECT ID
                                                                , pCode                           // 화면에서의 ??? Code Element의  Value
                                                                , pName                           // 화면에서의 ??? Name Element의  Value
                                                                , pClose                          // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                                                                , null                            // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                                                                , null                            // Title순서  
                                                                , null                            // 보여주는 각 컬럼들의 폭    
                                                                , null                            // 컬럼중에서 숨기는    컬럼 지정   
                                                                , null                            // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                                                , "400"                           // POP-UP뛰을때 원도우의   사용자 정의  폭
                                                                , null                            // POP-UP뛰을때 우도우의   사용자 정의  높이  
                                                                , null                            // 윈도우 위치 Y좌표   
                                                                , null                            // 윈도우 위치 X좌표
                                                                , null                            // 중복체크여부   ("F")
                                                                , pAllSearch                      // 전체검색허용여부 ("F")
                                                                , "차량번호,차량단축코드,차량번호"  // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                            );
            if (rtnList != null) {
                $c.gus.cfSetReturnValue(rtnList, ed_vehclNoCd, ed_vehclNo);
            }	
        break;
    }
};

// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        // inObj가 코드명 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.f_Save = async function () {
    for (var i = 0; i < ds_purchaseCerti.getRowCount(); i++) {
        if (ds_purchaseCerti.getCellData(i, "chk") == "T") {
            ds_purchaseCerti.setCellData(i, "drawEmpNo", scwin.vEmpNo); // 작성자코드
        }
    }	
    let e = await $c.sbm.execute(sbm_save);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_save_submitdone(e);
    }
};

// 세금계산서 출력
scwin.f_Print = async function() {
    var param = "";
    var printCnt = 0;

    var arrParam = [];
    var printCnt = 0;

    ds_purchaseEvidenceList.removeAll();

    for (var i = 0; i < ds_purchaseCerti.getRowCount(); i++) {
        if (ds_purchaseCerti.getCellData(i, "chk") == "T") {
            arrParam.push("to_char(" + ds_purchaseCerti.getCellData(i, "sellVatNo") + ")");
            scwin.f_SetDataSet(i); 
            printCnt++;
        }
    }
    var param = arrParam.join(",");

    if (printCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["발행할 세금계산서"]);  // @을(를) 선택하십시오.
        return;
    }

    const data = {
        reportName: "/ac/fi/taxbiz/vatctrl/fi_401_01_09p_1.ozr",
        odiName : "fi_401_01_09p",
        odiParam: {
            pchsSellCls : param,
        },
        viewerParam: {
            mode : "preview",
        },
        formParam: {}
    };

    await scwin.openPopup(data);

    // 세금계산서출력후 이력생성
    // ds_purchaseEvidenceList.UseChangeInfo = false;

    let e = await $c.sbm.execute(sbm_saveRegistTaxInvoiceHistory);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {

    }
};

scwin.openPopup = async function(data) {
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};

// Save or Del DataSet Setting
scwin.f_SetDataSet = function (row) {
  	// Save DataSet Setting	   
    var rowIndex = ds_purchaseEvidenceList.insertRow();
    ds_purchaseEvidenceList.setCellData(rowIndex, "slipNo", ds_purchaseCerti.getCellData(row, "slipNo"));
    ds_purchaseEvidenceList.setCellData(rowIndex, "pchsVatNo", ds_purchaseCerti.getCellData(row, "sellVatNo"));
    ds_purchaseEvidenceList.setCellData(rowIndex, "chk", ds_purchaseCerti.getCellData(row, "chk"));        
};

// 조회조기 필드 Clear
scwin.f_FieldClear = function () {
    ed_qryConDtFm.setValue(scwin.vQryStDt);
    ed_qryConDtTo.setValue(scwin.vQryEndDt);
    acb_qryDtConKnd.setValue("CERTI");  

    ed_homeClntNo.setValue(""); // 거래처번호
    ed_homeClntNm.setValue(""); // 거래처명

    acb_taxnClsCd.setValue("01");
};


//-------------------------------------------------------------------------
// 공통팝업호출 callBack
//-------------------------------------------------------------------------
// 계약거래처

//-------------------------------------------------------------------------
// Sbm submitdone
//-------------------------------------------------------------------------
scwin.sbm_searchCertiList_submitdone = async function (e) {
	totalRows.setValue(ds_purchaseCerti.getRowCount());

	ica_ed_slipCloseYm.setValue(ds_purchaseCerti.getCellData(0, "slipCloseYm"));  // 회계마감월
	ica_ed_taxCloseYm.setValue(ds_purchaseCerti.getCellData(0, "taxCloseYm"));	  // 세무마감월

	if (ds_purchaseCerti.getRowCount() == 0) { 
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002); 
	} else {
		for (var i = 0; i < ds_purchaseCerti.getRowCount(); i++) {
			ds_purchaseCerti.setCellData(i, "evidKndClsCd", "10");
			ds_purchaseCerti.setCellData(i, "taxnClsCd", "01");
		}	
	}		
};

scwin.sbm_save_submitdone = async function (e) {
	if (await $c.gus.cfAlertMsg(MSG_CM_INF_001)) { // 성공적으로 저장하였습니다
        scwin.f_Retrieve();	
    }	
};

//-------------------------------------------------------------------------
// Event onClick
//-------------------------------------------------------------------------
// 조회 버튼 클릭 이벤트 
scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

// 초기화 버튼 클릭 이벤트 
scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
};

// 세금계산서 접수 버튼 클릭 이벤트 
scwin.btn_Save_onclick = function (e) {
    scwin.f_Save();
};

// 세금계산서 출력 버튼 클릭 이벤트 
scwin.btn_Print_onclick = function (e) {
    scwin.f_Print();
};

// 소속거래처 찾기 버튼 클릭 이벤트 
scwin.udc_homeClntNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_homeClntNo.getValue(), ed_homeClntNm.getValue(), 'F', 'F');
};

// 차량번호 찾기 버튼 클릭 이벤트 
scwin.udc_vehclNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_vehclNoCd.getValue(), ed_vehclNo.getValue(), 'F', 'T');
};


//-------------------------------------------------------------------------
// Event onchange
//-------------------------------------------------------------------------

//-------------------------------------------------------------------------
// Event onblur
//-------------------------------------------------------------------------
// 소속거래처 Onbluer(onKillFocus) 이벤트 발생시
scwin.udc_homeClntNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_homeClntNo, ed_homeClntNm, 1);
};

// 차량번호 Onbluer(onKillFocus) 이벤트 발생시
scwin.udc_vehclNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_vehclNoCd, ed_vehclNo, 2);
};

//-------------------------------------------------------------------------
// Event onviewchange
//-------------------------------------------------------------------------
// 소속거래처 onviewchange 이벤트 발생시
scwin.udc_homeClntNo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_homeClntNm, ed_homeClntNo, 1, false);
};

// 차량번호 onviewchange 이벤트 발생시
scwin.udc_vehclNo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_vehclNo, ed_vehclNoCd, 2, false);
};

scwin.acb_qryDtConKnd_onviewchange = function (info) {
    ds_purchaseCerti.removeAll();
    $(gr_purchaseCerti.render).find(".nodata").hide();
};

//-------------------------------------------------------------------------
// DataSet 이벤트
//-------------------------------------------------------------------------

//-------------------------------------------------------------------------
// 그리드 이벤트
//-------------------------------------------------------------------------
scwin.gr_purchaseCerti_onheaderclick = function (headerId) {
    var i = 0;
    if (headerId == "chk")	{
        var bCheck = gr_out.getHeaderValue(headerId); 
        if (bCheck == "1") {
            for (var i = 0; i < ds_purchaseCerti.getRowCount(); i++) {
                ds_purchaseCerti.setCellData(i, "chk", "T"); 
            }
        } else {
            for (var i = 0; i < ds_purchaseCerti.getRowCount(); i++) {
                ds_purchaseCerti.setCellData(i, "chk", ""); 
            }
        }
    }
};

scwin.gr_purchaseCerti_oneditend = function (rowIndex, columnIndex, value) {
    var colid = gr_purchaseCerti.getColumnID(columnIndex); 

    if (colid == "evidKndClsCd") {
        if (ds_purchaseCerti.getCellData(rowIndex, "evidKndClsCd") == "10") {  // 증빙구분(세금계산서)
            ds_purchaseCerti.setCellData(rowIndex, "taxnClsCd", "01");  	// 과세구분(과세)			
        } else if (ds_purchaseCerti.getCellData(rowIndex, "evidKndClsCd") == "00") {
            ds_purchaseCerti.setCellData(rowIndex, "taxnClsCd", "02");
        }
    }
};

scwin.gr_purchaseCerti_oncellclick = async function (rowIndex, columnIndex, columnId) {
    if (columnId == "button" && rowIndex >= 0) {
        var	transRow;
		// 건별처리 PopUP 클릭시 Button의 체크 구분에 상관없이 "T"로 세팅 
 	    ds_purchaseCerti.setCellData(rowIndex, "chk", "T"); 

 	    // drawEmpNo(작성자)의 경우에는 조회조건이 거래명세서 일자의 경우만 작성자 데이터를 업데이트 한다. 
 	    if (acb_qryDtConKnd.getValue() == "CERTI") { 
	 		ds_purchaseCerti.setCellData(rowIndex, "drawEmpNo", scwin.vEmpNo); 	// 작성자코드 	    
 	    } 	

        $c.gus.cfCopyDataSetHeader(ds_purchaseCerti, ds_purchaseEvidence);

        transRow = ds_purchaseCerti.getRowJSON(rowIndex);
        ds_purchaseEvidence.insertRow();
        ds_purchaseEvidence.setRowJSON(0, transRow, true);  

	   	$c.gus.cfCopyDataSet(ds_purchaseCerti, ds_commonCopyList);

		var valueObject = {};
		valueObject.purchaseEvidence = ds_purchaseEvidence.getAllJSON();
		valueObject.commonList = ds_commonCopyList.getAllJSON();

        //상세화면 호출
	   	var opts = {
            id : "smpPop"	
          , popupName : "매입세금계산서 개별접수"
          , modal : true
          , type : "browserPopup"
          , width : 930
          , height : 716 
          , title : "매입세금계산서 개별접수"
        };

        const rtnList = await $c.win.openPopup("/ui/ja/dnja/adjm/dnja_210_02_02p.xml", opts, valueObject); 
        let e = await $c.sbm.execute(sbm_searchCertiList);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_searchCertiList_submitdone(e);
        }
    }
};

scwin.gr_purchaseCerti_onsort = function () {
    const $ele = $(this.render).find(".w2grid_head_sort_asc, .w2grid_head_sort_desc")
    if($ele.length === 0) {
        gr_purchaseCerti.setScrollTop(0);
    }
};
